GameAppShop = {}

function GameAppShop:onPlayerShopping(player, goodsId)
    local goods = AppShopConfig:getGoodsById(goodsId)
    if not goods then
        return false
    end
    player.taskController:packingProgressData(player, Define.TaskType.GrowUp.CostCoin, GameMatch.gameType, goods.PriceType, goods.Price)
    local goods_reward = RewardConfig:getRewardById(goods.RewardId)
    local rewardId = GameReward:onPlayerGetReward(player, goods_reward)
    if rewardId then
        GamePacketSender:sendPixelGunRewardResult(player.rakssid, rewardId)
    end
    return false
end

function GameAppShop:CanBuyGoods(player, goodsId)
    local goods = AppShopConfig:getGoodsById(goodsId)
    if not goods then
        return false
    end
    local money = 0
    if goods.PriceType == Define.Money.DIAMOND then
        money = player:getDiamond()
    end
    if goods.PriceType == Define.Money.GOLD then
        money = player:getGold()
    end
    if goods.PriceType == Define.Money.MONEY then
        money = player.money
    end
    if money < goods.Price then
        return false
    end
    return true
end

return GameAppShop